from flask import abort, json, jsonify, Blueprint
from api_base.routes.decorators import check_auth
from api_base.helpers import create_url, paginate_by
from api.models.user_profile import UserProfileModel

route = Blueprint('users', __name__)


@route.get(create_url('/users'), methods=['GET'])
def list():
    # return a json object containing a list of user profiles
    # paginated with the page parameter
    limit, offset = paginate_by()

    profiles = UserProfileModel().find() \
        .limit(limit) \
        .offset(offset) \
        .execute()

    count = UserProfileModel().find() \
        .count() \
        .execute()

    json_data = {
        'count': int(count),
        'next': None,  # will be set in the view function to point to the next page URL
        'previous': None,  # will be set in the view function to point to the previous page URL

        'results': [profile.json() for profile in profiles]
    }

    return jsonify(json_data)


@route.get(create_url('/users/<int:user_id>'), methods=['GET'])
def get(user_id):
    # retrieve a user's profile by id and provide their name, username, email, account type, referral code, and verified status
    user = UserProfileModel().find(user_id).execute()

    if not user:
        return abort(401)  # Unauthorized - user does not exist

    json_data = {
        'name': str(user['name']),

        'username': str(user['username']),

        'email': str(user['email']),

        'accountType': int(user['accountType'])
    }


@route.put(create_url('/users/<int:user_id>'), methods=['PUT'])
def put(user_id):
    # create a user's profile by updating the email, username, account type, credits, referral code and verified status fields for the given user id
    # set the updated user object to the new one in the request
    updated_user = UserProfileModel().find(user_id).execute()

    if not updated_user:
        return abort(401)  # Unauthorized - user does not exist


    json_data = {
            'email': str(updated_user['email']),

            'username': str(updated_user['username']),

            'accountType': int(updated_user['accountType'])

        }
    return jsonify(json_data)